    [Parameter] public RunState Run { get; set; } = null!;
    [Parameter] public MapNode Node { get; set; } = null!;
    [Parameter] public EventCallback OnEventEnd { get; set; }
    
    private EventDefinition? eventDef;
    private int goldAmount;
    private bool showCardSelection = false;
    private string selectionTitle = "";
    private string selectionDescription = "";
    private string selectionType = "";
    private int pendingChoiceIndex = -1;
    
    private bool showRewardModal = false;
    private int rewardGold = 0;
    private List<string> rewardCards = new();
    private string rewardMessage = "";
    
    protected override void OnInitialized()
    {
        if (Node.Type == "TREASURE")
        {
            var rng = new Random(Run.Seed + Run.CurrentFloor);
            goldAmount = rng.Next(50, 150);
        }
        else
        {
            eventDef = Database.Instance.GetEvent(Node.EventId ?? "");
        }
    }
    
    private List<CardInstance> GetSelectableCards()
    {
        if (selectionType == "UPGRADE")
            return Run.Deck.Where(c => !c.IsUpgraded).ToList();
        else if (selectionType == "REMOVE")
            return Run.Deck.ToList();
        return new List<CardInstance>();
    }
    
    private async Task SelectCard(string instanceId)
    {
        var rng = new Random(Run.Seed + Run.CurrentFloor);
        
        if (selectionType == "UPGRADE")
        {
            new RunManager().UpgradeCard(Run, instanceId);
            var card = Run.Deck.FirstOrDefault(c => c.InstanceId == instanceId);
            var cardDef = Database.Instance.GetCard(card?.CardId ?? "");
            eventDef!.Description += $"\n\n✨ Upgraded {cardDef?.Name}!";
        }
        else if (selectionType == "REMOVE")
        {
            var card = Run.Deck.FirstOrDefault(c => c.InstanceId == instanceId);
            var cardDef = Database.Instance.GetCard(card?.CardId ?? "");
            Run.Deck.Remove(card!);
            eventDef!.Description += $"\n\n🗑️ Removed {cardDef?.Name}!";
        }
        
        showCardSelection = false;
        
        // Process remaining effects from the choice
        if (pendingChoiceIndex >= 0 && eventDef != null)
        {
            var choice = eventDef.Choices[pendingChoiceIndex];
            foreach (var effect in choice.Effects)
            {
                if (effect.Type != "UPGRADE_CARD" && effect.Type != "REMOVE_CARD")
                {
                    new EventEngine(new RunManager()).ProcessEffect(Run, effect, rng);
                }
            }
        }
        
        StateHasChanged();
        
        // End the event after card selection
        await Task.Delay(500);
        await OnEventEnd.InvokeAsync();
    }
    
    private void CancelSelection()
    {
        showCardSelection = false;
        StateHasChanged();
    }
    
    private async Task ClaimTreasure()
    {
        new RunManager().AddGold(Run, goldAmount);
        await Task.Delay(500);
        await OnEventEnd.InvokeAsync();
    }
    
    private async Task MakeChoice(int choiceIndex)
    {
        if (eventDef == null) return;
        
        var choice = eventDef.Choices[choiceIndex];
        var rng = new Random(Run.Seed + Run.CurrentFloor);
        
        // Reset rewards
        rewardGold = 0;
        rewardCards.Clear();
        rewardMessage = "";
        
        var oldGold = Run.Gold;
        var oldDeckCount = Run.Deck.Count;
        
        // Check if choice requires card selection
        var needsUpgrade = choice.Effects.Any(e => e.Type == "UPGRADE_CARD");
        var needsRemove = choice.Effects.Any(e => e.Type == "REMOVE_CARD");
        
        if (needsUpgrade && Run.Deck.Any(c => !c.IsUpgraded))
        {
            selectionType = "UPGRADE";
            selectionTitle = "Select a card to upgrade";
            selectionDescription = "Choose a card from your deck to upgrade.";
            showCardSelection = true;
            pendingChoiceIndex = choiceIndex;
            
            // Process non-card effects first (like LOSE_GOLD, ADD_CURSE)
            foreach (var effect in choice.Effects)
            {
                if (effect.Type != "UPGRADE_CARD")
                {
                    new EventEngine(new RunManager()).ProcessEffect(Run, effect, rng);
                }
            }
            
            StateHasChanged();
            return;
        }
        else if (needsRemove && Run.Deck.Count > 0)
        {
            selectionType = "REMOVE";
            selectionTitle = "Select a card to remove";
            selectionDescription = "Choose a card to permanently remove from your deck.";
            showCardSelection = true;
            pendingChoiceIndex = choiceIndex;
            
            // Process non-card effects first
            foreach (var effect in choice.Effects)
            {
                if (effect.Type != "REMOVE_CARD")
                {
                    new EventEngine(new RunManager()).ProcessEffect(Run, effect, rng);
                }
            }
            
            StateHasChanged();
            return;
        }
        
        // Normal event processing
        new EventEngine(new RunManager()).ProcessEventChoice(Run, Node.EventId!, choiceIndex, rng);
        
        // Track rewards
        rewardGold = Run.Gold - oldGold;
        if (Run.Deck.Count > oldDeckCount)
        {
            var newCards = Run.Deck.Skip(oldDeckCount).ToList();
            rewardCards = newCards.Select(c => c.CardId).ToList();
        }
        
        // Check for curses
        var curseCards = Run.Deck.Where(c => 
            Database.Instance.GetCard(c.CardId)?.Rarity == "CURSE").ToList();
        if (curseCards.Count > oldDeckCount)
        {
            rewardMessage = "⚠️ A curse has been added to your deck!";
        }
        
        // Show rewards if any
        if (rewardGold != 0 || rewardCards.Count > 0 || !string.IsNullOrEmpty(rewardMessage))
        {
            showRewardModal = true;
            StateHasChanged();
        }
        else
        {
            await Task.Delay(1000);
            await OnEventEnd.InvokeAsync();
        }
    }
    
    private async Task Continue()
    {
        await OnEventEnd.InvokeAsync();
    }
    
    private async Task CloseRewardModal()
    {
        showRewardModal = false;
        StateHasChanged();
        await Task.Delay(300);
        await OnEventEnd.InvokeAsync();
    }
    
    private string GetDefaultTitle() => Node.Type switch
    {
        "NPC" => "🧙 Mysterious Stranger",
        "TRADER" => "🛒 Traveling Trader",
        "BLESSING" => "✨ Divine Blessing",
        _ => "Encounter"
    };
    
    private string GetDefaultDescription() => Node.Type switch
    {
        "NPC" => "A mysterious figure nods at you and disappears into the shadows.",
        "TRADER" => "The trader has nothing of interest today.",
        "BLESSING" => "You feel a warm presence, but nothing happens.",
        _ => "Nothing of note occurs here."
    };

